VALUES
  ('judicial-7acda994-moex-00044', 'judicial-7acda994', 'judicial-7acda994-moex-112-de0a21a2', 'sub-judicial-7acda994-01', NULL, 'essay', '甲涉嫌基於意圖營利之犯意，以新臺幣 3,000 元，販賣第一級毒品海洛
因給乙，經檢察官依法向法院聲請搜索票後，於甲之住處扣得第一級毒
品海洛因及前揭買賣毒品之款項，檢察官以甲涉犯上開罪嫌重大、符合
羈押事由及有羈押之必要性，依法聲請法院羈押獲准，嗣檢察官於蒐證
完畢後，就上開案件提起公訴而經法院進行審理。試問：何謂「嚴格之
證明」、「自由之證明」？請說明於刑事程序中，何種事項須經「嚴格之
證明」、何種事項僅以「自由之證明」即可？並請就上開案件中，關於認
定「搜索」、「羈押」及「甲有販賣第一級毒品」等事實，論述是否需要
經「嚴格之證明」？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "9f777757f90a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00045', 'judicial-7acda994', 'judicial-7acda994-moex-112-de0a21a2', 'sub-judicial-7acda994-01', NULL, 'essay', '檢察官偵辦甲涉犯詐欺取財罪及一般洗錢罪之案件，先就詐欺取財罪部
分向法院提起公訴，經該法院審核該案卷證資料後，認為已起訴之詐欺
取財罪部分與未起訴之一般洗錢罪部分具有「想像競合犯」裁判上一罪
之關係。請論述檢察官就本案之詐欺取財罪部分起訴，效力是否及於一
般洗錢罪部分？依目前實務之作法，檢察官就該一般洗錢罪部分，通常
係以如何之方式請求法院併予審理？得否就一般洗錢罪部分另行起
訴？倘檢察官就一般洗錢罪部分又向同一法院提起公訴，法院對於該另
行起訴之一般洗錢罪部分，應為如何之處理？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "9f777757f90a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00046', 'judicial-7acda994', 'judicial-7acda994-moex-112-4bf6d96a', 'sub-judicial-7acda994-02', NULL, 'essay', '原告甲將 A車以新臺幣（下同）500 萬元價格售予乙，並與乙協議為：
乙先給付現金 200 萬元後，甲即交車予乙，並同意其餘 300萬元，由乙
分 3 期給付予甲。嗣後乙卻未依約履行。甲起訴請求被告乙給付價款300
萬元，而於第一審言詞辯論期日時，乙表示無力給付，嗣後經審判長試
行和解，加入第三人乙父丙，達成訴訟上和解為：由乙父丙給付甲 300
萬元。請分析第三人丙加入和解之效力，並說明若嗣後丙以其同意參加
和解係被詐欺所致，並否認上開和解之效力、拒不履行和解內容，則原
告甲得否主張和解不成立、繼續審判？（33分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "625a52f085a0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "104", "s": "0406", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00047', 'judicial-7acda994', 'judicial-7acda994-moex-112-4bf6d96a', 'sub-judicial-7acda994-02', NULL, 'essay', '甲在乙所開設之美容工作室工作四年餘，今甲聲稱乙故意製造敵意與性
別霸凌環境、逼迫自己離職，致甲訴請乙給付其資遣費新臺幣（下同）
200 萬元。第一審判決甲全部敗訴。乙於第二審行準備程序時，提出反
訴主張甲離職後，違反僱傭契約之競業禁止條款，故依約應給付乙違約
金 220萬元。試問第二審法院應如何處理乙所提出之反訴？（33分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "625a52f085a0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "104", "s": "0406", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00048', 'judicial-7acda994', 'judicial-7acda994-moex-112-4bf6d96a', 'sub-judicial-7acda994-02', NULL, 'essay', '甲購入A地，市價新臺幣2,000萬元。詎料遭友人乙竊取印章移轉A地於
乙名下，致甲起訴請求返還。然於訴訟繫屬中，被告乙將 A 地以新臺幣
200萬元賣給不知情的丙並移轉登記。請分析如乙將A地移轉登記予丙，
對本件訴訟影響；並說明如丙於第一審判決時，為訴訟參加，並於乙受第
一審敗訴判決時，為乙聲明上訴，丙之行為效力為何？（34分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "625a52f085a0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "104", "s": "0406", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00049', 'judicial-7acda994', 'judicial-7acda994-moex-112-9b7ab1bb', 'sub-judicial-7acda994-03', NULL, 'essay', '開設 A 油漆行之甲，某日竊取乙之 10 桶油漆，置放於 A 油漆行販售。
一個月後，不知情之丙向甲購買其中 7桶油漆，並將之使用於丙新購買
之 B屋牆壁。又經三個月，乙發現甲竊取油漆及將部分油漆出售給丙，
以及丙將該油漆使用於 B屋牆壁等情事。試問：乙對甲、丙該如何主張
權利？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "9d41826a9492", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "104", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00050', 'judicial-7acda994', 'judicial-7acda994-moex-112-9b7ab1bb', 'sub-judicial-7acda994-03', NULL, 'essay', '甲移居美國前，將登記其名下之A屋委託好友乙管理。不久，乙死亡，
丙見 A 屋長久無人居住而潛入該屋居住。丙居住 16 年後，甲返國得知
丙居住 A 屋，遂請求丙歸還 A 屋，丙則抗辯甲請求歸還 A 屋之權利已
消滅時效完成，而拒絕歸還 A屋。試問：丙之抗辯是否有理？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "9d41826a9492", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "104", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00051', 'judicial-7acda994', 'judicial-7acda994-moex-112-9b7ab1bb', 'sub-judicial-7acda994-03', NULL, 'essay', '甲因重病而生命垂危，故以錄音方式作成口授遺囑，並指定乙及丙為見
證人。甲之配偶已過世，並生有二子 A及 B，而甲於遺囑中指定A應繼
分為三分之二，並對其姪子 C遺贈新臺幣300萬元。三個月後甲病情好
轉痊癒，但於口授遺囑完成二年後，甲因車禍死亡。試問：A及C得否
依口授遺囑之內容主張該權利？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "9d41826a9492", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "104", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00052', 'judicial-7acda994', 'judicial-7acda994-moex-112-9b7ab1bb', 'sub-judicial-7acda994-03', NULL, 'essay', '甲新購買位於 12 層樓之 A屋，搬家遷入 A屋時，其支付移機費委託乙
將原居住 B屋之三部冷氣機移機裝設至 A屋。然而，因乙之助手丙工作
疏失而未固定好冷氣機，導致其中一部冷氣機從高樓掉落而擊中路過之
上班族丁，丁當場不治死亡。另一位上班族戊，則因閃避掉落之冷氣機
而跌倒，小腿骨折住院治療一個月，而戊之母親己於此一個月間擔任戊
之看護。試問：甲、乙及丙對此冷氣機掉落事件該如何負責？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "9d41826a9492", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "104", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00053', 'judicial-7acda994', 'judicial-7acda994-moex-112-0835bf52', 'sub-judicial-7acda994-04', NULL, 'essay', '甲經核准於 A 直轄市經營 B 民宿 5 間客房。A 直轄市政府觀光旅遊局
（下稱 A觀光局）發現，B民宿有違反民宿管理辦法第 30條第 5款「擅
自擴大經營規模」之情事，A 觀光局乃依發展觀光條例第 55 條第 7 項
規定裁處甲 9萬元罰鍰，擴大部分於文到 3日內歇業。甲不服，主張依
發展觀光條例第 3 條之規定，A直轄市政府始為管轄機關，A觀光局並
無發展觀光條例之管轄權；A觀光局對甲之裁罰處分，既「缺乏事務權
限」，依行政程序法第 111 條第 6款之規定，應屬無效。試問：甲主張有
無理由？（25 分）
參考法條：
發展觀光條例第3條：「本條例所稱主管機關：在中央為交通部；在直轄市為直轄市
政府；在縣（市）為縣（市）政府。」
發展觀光條例第55條第7項：「觀光旅館業、旅館業及民宿經營者，擅自擴大營業客
房部分者，其擴大部分，觀光旅館業及旅館業處新臺幣五萬元以上二十五萬元以下
罰鍰。民宿經營者處新臺幣三萬元以上十五萬元以下罰鍰。擴大部分並勒令歇業。」
A市政府組織自治條例第6條第1項第8款、第2項：「（第1項）本府設下列各局、處、
委員會：……八、觀光局。（第2項)各局、處、委員會之組織規程，由本府另定之。」
A市政府觀光旅遊局組織規程第3條：「（第1項）觀光旅遊局設下列科、室，分別掌
理各有關事項：……二、觀光管理科：旅行業、旅館業、民宿、觀光遊樂業、溫泉
使用事業等觀光產業之輔導與管理、水域遊憩活動管理及督導風景區營運管理等
事項。」', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "196e28dbbb74", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "104", "s": "0308", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政程序法與行政執行法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL)
